class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def segregate_even_odd_nodes(head: ListNode) -> ListNode:
    if not head:
        return None

    even_head = None
    even_tail = None
    odd_head = None
    odd_tail = None

    current = head
    while current:
        if current.val % 2 == 0:  # Even node
            if even_head is None:
                even_head = current
                even_tail = current
            else:
                even_tail.next = current
                even_tail = current
        else:  # Odd node
            if odd_head is None:
                odd_head = current
                odd_tail = current
            else:
                odd_tail.next = current
                odd_tail = current

        current = current.next

    # Terminate the even and odd lists
    if even_tail:
        even_tail.next = None
    if odd_tail:
        odd_tail.next = None

    # Connect the even list to the odd list
    if even_head is None:
        # No even nodes, return the odd list
        return odd_head
    else:
        # Connect the tail of the even list to the head of the odd list
        even_tail.next = odd_head
        # Return the head of the even list
        return even_head
